SELECT id, path, name, city FROM stores WHERE city='Graz' ORDER BY name LIMIT 20;

SELECT brand, model, series, name, path FROM products WHERE brand='Dresselhaus' AND model='1VG-P5G' LIMIT 10;
SELECT brand, model, series, name, path FROM products WHERE brand='Fischer' AND model='7UY-G03' LIMIT 10;
SELECT brand, model, series, name, path FROM products WHERE brand='Bahco' AND model='3VZ-SPH' LIMIT 10;
SELECT brand, model, series, name, path FROM products WHERE brand='Makita' AND model='OIE-YYP' LIMIT 10;
SELECT brand, model, series, name, path FROM products WHERE brand='Keter' AND model='2OO-VJU' LIMIT 10;
SELECT brand, model, series, name, path FROM products WHERE brand='Schneider Electric' AND model='214-ZHY' LIMIT 10;

SELECT id, path, name, city FROM stores WHERE city='Brno' AND name LIKE '%Veveri%PowerTool%' LIMIT 10; 

SELECT sku, path, brand, series, model, name FROM products WHERE brand='Hansgrohe' AND series LIKE '%Hansgrohe Raindance%' AND model='Raindance 1X3-24A' AND kind_id='valves_connectors' AND json_extract(properties,'$.connector_type')='ball valve' LIMIT 5;

SELECT sku, path, brand, series, model, name FROM products WHERE brand='Stihl' AND series LIKE '%Stihl Power%' AND model='MS 3QU-76F' AND kind_id='trimmers_blowers' AND json_extract(properties,'$.tool_type')='leaf blower' AND json_extract(properties,'$.power_source')='battery' LIMIT 5;

SELECT sku, path, brand, series, model, name FROM products WHERE brand='Sikkens' AND series LIKE '%Sikkens Quick Dry%' AND model='Rubbol 2ZM-4Z1' AND kind_id='wall_paint' AND json_extract(properties,'$.color_family')='Clear' LIMIT 5;

SELECT sku, path, brand, series, model, name FROM products WHERE brand='Viega' AND series LIKE '%Viega Professional%' AND model='Smartpress 37V-8FZ' AND kind_id='pipe_fittings' AND json_extract(properties,'$.fitting_type')='pipe fitting' AND json_extract(properties,'$.diameter')='16 mm' AND json_extract(properties,'$.connection_type')='push fit' AND json_extract(properties,'$.thread_type')='M24' LIMIT 5;

SELECT sku, path, brand, series, model, name FROM products WHERE brand='Sonax' AND series LIKE '%Sonax Premium Gloss%' AND model='A0Q-MOK' AND kind_id='wiper_blades' AND json_extract(properties,'$.length')='650 mm' AND json_extract(properties,'$.adapter_type')='hook' AND json_extract(properties,'$.vehicle_type')='van' LIMIT 5;

SELECT sku, path, brand, series, model, name FROM products WHERE brand='DeWalt' AND series LIKE '%DeWalt XR%' AND model='DW Y8M-P6Z' AND kind_id='cordless_drill_drivers' AND json_extract(properties,'$.voltage')='18 V' AND json_extract(properties,'$.battery_platform')='18v-system' AND json_extract(properties,'$.kit_contents')='bare tool' LIMIT 5;

SELECT id, path, name, city FROM stores WHERE city='Brno' ORDER BY name LIMIT 50;

SELECT sku, path, brand, series, model, kind_id FROM products WHERE brand='Viega' AND model='Smartpress 37V-8FZ' LIMIT 20;
SELECT sku, path, brand, series, model, kind_id FROM products WHERE brand='Sonax' AND model='A0Q-MOK' LIMIT 20;

SELECT DISTINCT json_extract(properties,'$.connector_type') AS connector_type FROM products WHERE brand='Hansgrohe' AND series='Raindance' AND model='Raindance 1X3-24A' ORDER BY 1;
SELECT DISTINCT json_extract(properties,'$.tool_type') AS tool_type, json_extract(properties,'$.power_source') AS power_source FROM products WHERE brand='Stihl' AND series='Power' AND model='MS 3QU-76F' ORDER BY 1,2;
SELECT DISTINCT json_extract(properties,'$.color_family') AS color_family FROM products WHERE brand='Sikkens' AND series='Quick Dry' AND model='Rubbol 2ZM-4Z1' ORDER BY 1;
SELECT DISTINCT json_extract(properties,'$.voltage') AS voltage, json_extract(properties,'$.battery_platform') AS battery_platform, json_extract(properties,'$.kit_contents') AS kit_contents FROM products WHERE brand='DeWalt' AND series='XR' AND model='DW Y8M-P6Z' ORDER BY 1,2,3;
